import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

def process_files(data, context):
    # Get the file name from the event data
    file_name = data['name']
    
    # Instantiate a client for Google Cloud Storage, Firestore and Pub/Sub
    storage_client = storage.Client()
    firestore_db = firestore.Client()
    publisher = pubsub_v1.PublisherClient()
    
    # Get the bucket where the file is located
    bucket_name = os.getenv('GCS_BUCKET')
    bucket = storage_client.bucket(bucket_name)
    
    # Download the file from GCS to a temporary location
    blob = bucket.blob(file_name)
    temp_local_filename = '/tmp/' + file_name
    blob.download_to_filename(temp_local_filename)
    
    # TODO: Process the downloaded file (e.g., parse it, transform data etc.) 
    # This is a placeholder for actual processing logic
    
    # Write to Firestore
    firestore_doc = { 'fileName': file_name }
    firestore_db.collection('processedFiles').document(file_name).set(firestore_doc)
    
    # Publish message on Pub/Sub
    topic_path = publisher.topic_path(os.getenv('PUBSUB_TOPIC'))
    data = 'New file processed: {}'.format(file_name)
    publisher.publish(topic_path, data=data.encode())